#include <stdio.h>
#include <string.h>

int main() {
    int t;
    scanf("%d", &t);

    while (t--) {
        char s[1001];
        scanf("%s", s);
        int count_a = 0, count_b = 0;
        int n = strlen(s);

        for (int i = 0; i < n; i++) {
            if (s[i] == 'a') count_a++;
            else count_b++;
        }

        printf("%d\n", (count_a < count_b) ? count_a : count_b);
    }

    return 0;
}

